def test_sieve_correctly_identifies_primes():
    primes = sieve(7)
    assert primes == [2, 3, 5, 7, 11], "Sieve should correctly identify only the primes up to 7"

def sieve(max):
    primes = []
    for n in range(2, max + 1):
        if all(n % p != 0 for p in primes):
            for p in primes:
                if n % p == 0:
                    break
            else:
                primes.append(n)
    return primes
